// Verify HMAC signature
const crypto = require('crypto');

const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) {
  throw new Error('Missing x-profunda-signature header');
}

if (!webhookBody || typeof webhookBody !== 'object') {
  throw new Error('Missing or invalid webhook body');
}

if (webhookBody.workflow_key !== 'watchlist_deep_dive') {
  throw new Error('workflow_key must be watchlist_deep_dive, got: ' + webhookBody.workflow_key);
}

if (!webhookBody.run_id || typeof webhookBody.run_id !== 'string') {
  throw new Error('Missing run_id');
}

// Compute HMAC over the raw body JSON
const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');

if (hmac !== signature) {
  throw new Error('Invalid HMAC signature');
}

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!input.org_id || typeof input.org_id !== 'string' || !UUID_RE.test(input.org_id)) {
  throw new Error('org_id must be a valid UUID');
}

const validDepths = ['light', 'standard'];
const depth = (typeof input.depth === 'string' && validDepths.includes(input.depth))
  ? input.depth
  : 'standard';

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'watchlist_deep_dive',
    org_id: input.org_id,
    org_name: input.org_name || null,
    website_url: input.website_url || null,
    depth: depth,
    triggered_by: input.triggered_by || null
  }
}];

// Resolve the website URL to crawl
const validated = $('Validate Input').first().json;
const fetchResult = $('Fetch Org Context').first().json;

// Prefer validated input, then watchlist record, then null
let websiteUrl = validated.website_url;

if (!websiteUrl && Array.isArray(fetchResult) && fetchResult.length > 0) {
  websiteUrl = fetchResult[0].website_url;
} else if (!websiteUrl && fetchResult && fetchResult.website_url) {
  websiteUrl = fetchResult.website_url;
}

if (!websiteUrl || typeof websiteUrl !== 'string' || !websiteUrl.trim()) {
  return [{
    json: {
      run_id: validated.run_id,
      org_id: validated.org_id,
      website_url: null,
      crawl_skipped: true,
      skip_reason: 'No website URL available for org',
      watchlist_record: Array.isArray(fetchResult) ? fetchResult[0] || null : fetchResult
    }
  }];
}

// Normalize URL
let normalized = websiteUrl.trim();
if (!/^https?:\/\//i.test(normalized)) {
  normalized = 'https://' + normalized;
}

return [{
  json: {
    run_id: validated.run_id,
    org_id: validated.org_id,
    depth: validated.depth,
    website_url: normalized,
    crawl_skipped: false,
    watchlist_record: Array.isArray(fetchResult) ? fetchResult[0] || null : fetchResult
  }
}];

// Extract deterministic signals from scraped content
const resolveData = $('Resolve URL').first().json;
const run_id = resolveData.run_id;
const org_id = resolveData.org_id;

// Check if crawl was skipped
if (resolveData.crawl_skipped) {
  return [{
    json: {
      run_id,
      org_id,
      signals: [],
      signal_count: 0,
      crawl_skipped: true,
      skip_reason: resolveData.skip_reason
    }
  }];
}

let scrapeData;
try {
  scrapeData = $('Firecrawl Scrape').first().json;
} catch (e) {
  return [{
    json: {
      run_id,
      org_id,
      signals: [],
      signal_count: 0,
      crawl_error: 'Firecrawl node did not produce output: ' + String(e.message).slice(0, 200)
    }
  }];
}

// Check for Firecrawl errors
if (scrapeData.error || !scrapeData.success) {
  return [{
    json: {
      run_id,
      org_id,
      signals: [],
      signal_count: 0,
      crawl_error: scrapeData.error || 'Firecrawl returned unsuccessful response'
    }
  }];
}

const markdown = scrapeData.data?.markdown || scrapeData.markdown || '';
const links = scrapeData.data?.links || scrapeData.links || [];
const metadata = scrapeData.data?.metadata || scrapeData.metadata || {};

// Deterministic signal extraction from content
const signals = [];
const contentLower = markdown.toLowerCase();

// Signal: page size / content richness
if (markdown.length > 0) {
  signals.push({
    signal_type: 'content_size',
    summary: `Page content: ${markdown.length} chars, ${links.length} links found`,
    confidence: 1.0,
    metadata: { char_count: markdown.length, link_count: links.length }
  });
}

// Signal: detect hiring/growth keywords
const hiringKeywords = ['hiring', 'careers', 'job openings', 'we are growing', 'join our team', 'open positions'];
const hiringMatches = hiringKeywords.filter(kw => contentLower.includes(kw));
if (hiringMatches.length > 0) {
  signals.push({
    signal_type: 'hiring_activity',
    summary: `Hiring signals detected: ${hiringMatches.join(', ')}`,
    confidence: 0.8,
    metadata: { matched_keywords: hiringMatches }
  });
}

// Signal: detect partnership/expansion keywords
const expansionKeywords = ['new location', 'expanding', 'partnership', 'launched', 'announcement', 'press release'];
const expansionMatches = expansionKeywords.filter(kw => contentLower.includes(kw));
if (expansionMatches.length > 0) {
  signals.push({
    signal_type: 'expansion_activity',
    summary: `Expansion/partnership signals: ${expansionMatches.join(', ')}`,
    confidence: 0.7,
    metadata: { matched_keywords: expansionMatches }
  });
}

// Signal: detect technology/digital equity keywords
const techKeywords = ['digital equity', 'broadband', 'computer', 'device', 'technology access', 'digital inclusion', 'digital literacy'];
const techMatches = techKeywords.filter(kw => contentLower.includes(kw));
if (techMatches.length > 0) {
  signals.push({
    signal_type: 'tech_relevance',
    summary: `Digital equity relevance detected: ${techMatches.join(', ')}`,
    confidence: 0.85,
    metadata: { matched_keywords: techMatches }
  });
}

// Signal: detect funding/grant keywords
const fundingKeywords = ['funding', 'grant', 'awarded', 'million', 'investment', 'fundrais'];
const fundingMatches = fundingKeywords.filter(kw => contentLower.includes(kw));
if (fundingMatches.length > 0) {
  signals.push({
    signal_type: 'funding_activity',
    summary: `Funding/grant signals: ${fundingMatches.join(', ')}`,
    confidence: 0.75,
    metadata: { matched_keywords: fundingMatches }
  });
}

// Signal: page metadata
if (metadata.title || metadata.description) {
  signals.push({
    signal_type: 'page_metadata',
    summary: `Title: ${(metadata.title || 'N/A').slice(0, 100)}`,
    confidence: 1.0,
    metadata: { title: metadata.title, description: (metadata.description || '').slice(0, 300), source_url: metadata.sourceURL || resolveData.website_url }
  });
}

return [{
  json: {
    run_id,
    org_id,
    signals,
    signal_count: signals.length,
    source_url: resolveData.website_url,
    crawl_error: null
  }
}];

// Skip path: no URL available, still produce envelope
const resolveData = $('Resolve URL').first().json;

return [{
  json: {
    run_id: resolveData.run_id,
    org_id: resolveData.org_id,
    signals: [],
    signal_count: 0,
    crawl_skipped: true,
    skip_reason: resolveData.skip_reason || 'No website URL',
    crawl_error: null
  }
}];

const validated = $('Validate Input').first().json;

// Try to get signal data from either path
let signalData = null;
let error = null;
let failed_node = null;

try {
  signalData = $('Extract Signals').first().json;
} catch (e1) {
  try {
    signalData = $('Skip Crawl').first().json;
  } catch (e2) {
    error = 'Neither Extract Signals nor Skip Crawl produced output';
    failed_node = 'Extract Signals';
  }
}

if (signalData && signalData.crawl_error) {
  error = signalData.crawl_error;
  failed_node = 'Firecrawl Scrape';
}

let result = null;
if (!error && signalData) {
  result = {
    signals: signalData.signals || [],
    signal_count: signalData.signal_count || 0,
    org_id: signalData.org_id,
    source_url: signalData.source_url || null,
    crawl_skipped: signalData.crawl_skipped || false
  };
}

return [{
  json: {
    run_id: validated.run_id,
    workflow_key: 'watchlist_deep_dive',
    payload: {
      result: result,
      error: error,
      failed_node: failed_node
    }
  }
}];
